package com.chaobo.scm.supplier.infrastructure.persistence.rfq;import org.apache.ibatis.annotations.*;import java.time.*;
@Mapper public interface SupplierQuoteTodoMapper{record TodoState(int status,OffsetDateTime deadline){}@Insert("INSERT INTO sup_supplier_quote_todo(todo_id,rfq_id,rfq_no,supplier_id,quote_deadline,todo_status,rfq_snapshot_json) VALUES(#{id},#{rfqId},#{rfqNo},#{supplierId},#{deadline},1,CAST(#{snapshot} AS JSON)) ON DUPLICATE KEY UPDATE quote_deadline=VALUES(quote_deadline),rfq_snapshot_json=VALUES(rfq_snapshot_json),todo_status=IF(todo_status=3,3,1)")void upsert(@Param("id")long id,@Param("rfqId")long rfqId,@Param("rfqNo")String rfqNo,@Param("supplierId")long supplierId,@Param("deadline")OffsetDateTime deadline,@Param("snapshot")String snapshot);@Select("SELECT todo_status status,quote_deadline deadline FROM sup_supplier_quote_todo WHERE rfq_id=#{rfqId} AND supplier_id=#{supplierId}")TodoState state(@Param("rfqId")long rfqId,@Param("supplierId")long supplierId);@Update("UPDATE sup_supplier_quote_todo SET todo_status=2,version=version+1 WHERE rfq_id=#{rfqId} AND supplier_id=#{supplierId} AND todo_status=1")int markSubmitted(@Param("rfqId")long rfqId,@Param("supplierId")long supplierId);@Update("UPDATE sup_supplier_quote_todo SET todo_status=3,version=version+1 WHERE rfq_id=#{rfqId} AND todo_status IN (1,2)")int close(@Param("rfqId")long rfqId);}
